package main

import (
	"flag"
	"os"
	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/picod"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(nil)

	port := flag.Int("port", 8080, "Port for the PicoD server to listen on")
	workspace := flag.String("workspace", "", "Root directory for file operations (default: current working directory)")

	flag.Parse()

	config := picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server, err := picod.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
		os.Exit(1)
	}

	stopCh := make(chan os.Signal, 1)
	signal.Notify(stopCh, syscall.SIGINT, syscall.SIGTERM)

	errCh := make(chan error, 1)
	go func() {
		errCh <- server.Run()
	}()

	select {
	case err := <-errCh:
		if err != nil {
			klog.Fatalf("Server error: %v", err)
		}
	case <-stopCh:
		klog.Info("Shutting down PicoD server...")
		if err := server.Shutdown(nil); err != nil {
			klog.Errorf("Error during shutdown: %v", err)
		}
		klog.Info("PicoD server stopped")
	}
}

