package agentd

import (
	"context"
	"time"

	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/runtime"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/log"

	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

var SessionExpirationTimeout = 15 * time.Minute

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	logger := log.FromContext(ctx)

	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			return ctrl.Result{}, nil
		}
		logger.Error(err, "Failed to get Sandbox", "namespace", req.Namespace, "name", req.Name)
		return ctrl.Result{}, err
	}

	lastActivityStr, exists := sandbox.Annotations[workloadmanager.LastActivityAnnotationKey]
	if !exists || lastActivityStr == "" {
		logger.V(4).Info("Sandbox has no last-activity-time annotation, skipping",
			"namespace", sandbox.Namespace, "name", sandbox.Name)
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		logger.Error(err, "Failed to parse last-activity-time", "value", lastActivityStr)
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	now := time.Now()

	if now.After(expirationTime) {
		logger.Info("Sandbox is expired, deleting",
			"namespace", sandbox.Namespace,
			"name", sandbox.Name,
			"lastActivity", lastActivity,
			"expirationTime", expirationTime)

		if err := r.Delete(ctx, sandbox); err != nil {
			if errors.IsNotFound(err) {
				logger.Info("Sandbox already deleted", "namespace", sandbox.Namespace, "name", sandbox.Name)
				return ctrl.Result{}, nil
			}
			logger.Error(err, "Failed to delete expired Sandbox",
				"namespace", sandbox.Namespace, "name", sandbox.Name)
			return ctrl.Result{}, err
		}

		logger.Info("Successfully deleted expired Sandbox",
			"namespace", sandbox.Namespace, "name", sandbox.Name)
		return ctrl.Result{}, nil
	}

	requeueAfter := time.Until(expirationTime)
	if requeueAfter < 0 {
		requeueAfter = 0
	}

	logger.V(4).Info("Sandbox not yet expired, requeuing",
		"namespace", sandbox.Namespace,
		"name", sandbox.Name,
		"requeueAfter", requeueAfter,
		"expirationTime", expirationTime)

	return ctrl.Result{RequeueAfter: requeueAfter}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(r)
}

