)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	transport := &http.Transport{
		MaxIdleConnsPerHost: 100,
		DisableCompression:  false,
	}

	if err := http2.ConfigureTransports(transport); err != nil {
		klog.Warningf("Failed to configure HTTP/2 transport: %v", err)
	}

	httpClient := &http.Client{
		Timeout:   2 * time.Minute,
		Transport: transport,
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: strings.TrimSuffix(workloadMgrAddr, "/"),
		httpClient:      httpClient,
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err == store.ErrNotFound {
		return nil, api.NewSessionNotFoundError(sessionID)
	}
	if err != nil {
		klog.Errorf("Failed to get sandbox from store: %v", err)
		return nil, err
	}

	if sandbox != nil {
		return sandbox, nil
	}

	if kind == types.AgentRuntimeKind || kind == types.CodeInterpreterKind {
		return m.createSession(ctx, namespace, name, kind)
	}

	return nil, api.NewSessionNotFoundError(sessionID)
}

func (m *manager) createSession(ctx context.Context, namespace, name, kind string) (*types.SandboxInfo, error) {
	var endpoint string
	if kind == types.AgentRuntimeKind {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	} else if kind == types.CodeInterpreterKind {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	} else {
		return nil, fmt.Errorf("unsupported kind: %s", kind)
	}

	reqBody := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	jsonData, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, bytes.NewReader(jsonData))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")

	if token := m.loadWorkloadManagerAuthToken(); token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := m.httpClient.Do(req)
	if err != nil {
		klog.Errorf("Failed to call workload manager: %v", err)
		return nil, err
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response body: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		klog.Errorf("Workload manager returned status %d: %s", resp.StatusCode, string(body))
		if resp.StatusCode == http.StatusNotFound {
			return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
		}
		return nil, fmt.Errorf("workload manager returned %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.Unmarshal(body, &createResp); err != nil {
		return nil, fmt.Errorf("failed to unmarshal response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("sessionId is empty in workload manager response")
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        createResp.SandboxID,
		SandboxNamespace: namespace,
		Name:             createResp.SandboxName,
		SessionID:        createResp.SessionID,
		EntryPoints:      createResp.EntryPoints,
		CreatedAt:        time.Now(),
		Status:           "running",
	}

	klog.Infof("Created new session %s for %s/%s (kind=%s)",
		createResp.SessionID, namespace, name, kind)

	return sandboxInfo, nil
}

func (m *manager) loadWorkloadManagerAuthToken() string {
	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	tokenBytes, err := os.ReadFile(tokenPath)
	if err != nil {
		if !os.IsNotExist(err) {
			klog.Warningf("Failed to read service account token: %v", err)
		}
		return ""
	}

	return strings.TrimSpace(string(tokenBytes))
}

func (m *manager) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	return m.storeClient.GetSandboxBySessionID(ctx, sessionID)
}

