*/

package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"sync"
	"time"

	"github.com/golang-jwt/jwt/v5"
	v1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	rsaKeySize         = 2048
	jwtExpiration      = 5 * time.Minute
	IdentitySecretName = "picod-router-identity"
	PrivateKeyDataKey  = "private.pem"
	PublicKeyDataKey   = "public.pem"
)

var IdentityNamespace = "default"

func init() {
	if ns := os.Getenv("AGENTCUBE_NAMESPACE"); ns != "" {
		IdentityNamespace = ns
	}
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
	mutex      sync.RWMutex
}

func NewJWTManager() (*JWTManager, error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key: %w", err)
	}

	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}, nil
}

func (jm *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now()

	tokenClaims := jwt.MapClaims{
		"exp": now.Add(jwtExpiration).Unix(),
		"iat": now.Unix(),
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		tokenClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)

	jm.mutex.RLock()
	defer jm.mutex.RUnlock()

	if jm.privateKey == nil {
		return "", fmt.Errorf("private key not loaded")
	}

	signedToken, err := token.SignedString(jm.privateKey)
	if err != nil {
		return "", fmt.Errorf("failed to sign token: %w", err)
	}

	return signedToken, nil
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Warningf("Not running in cluster, using ephemeral keys: %v", err)
		return nil
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	jm.clientset = clientset

	secret := &v1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
			Labels: map[string]string{
				"app":       "agentcube",
				"component": "router",
			},
		},
		Type: v1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: PrivateKeyToPEM(jm.privateKey),
			PublicKeyDataKey:  PublicKeyToPEM(jm.publicKey),
		},
	}

	createdSecret, err := clientset.CoreV1().Secrets(IdentityNamespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if errors.IsAlreadyExists(err) {
			klog.Infof("Identity secret %s/%s already exists, loading existing key", IdentityNamespace, IdentitySecretName)
			return jm.loadExistingSecret(ctx)
		}
		return fmt.Errorf("failed to create identity secret: %w", err)
	}

	klog.Infof("Created identity secret %s/%s", IdentityNamespace, IdentitySecretName)
	_ = createdSecret
	return nil
}

func (jm *JWTManager) loadExistingSecret(ctx context.Context) error {
	existing, err := jm.clientset.CoreV1().Secrets(IdentityNamespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		return fmt.Errorf("failed to get existing identity secret: %w", err)
	}

	privateKeyPEM := existing.Data[PrivateKeyDataKey]
	if len(privateKeyPEM) == 0 {
		return fmt.Errorf("private key not found in secret")
	}

	block, _ := pem.Decode(privateKeyPEM)
	if block == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicKeyPEM := existing.Data[PublicKeyDataKey]
	if len(publicKeyPEM) == 0 {
		return fmt.Errorf("public key not found in secret")
	}

	block, _ = pem.Decode(publicKeyPEM)
	if block == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	pubInterface, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	publicKey, ok := pubInterface.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("not an RSA public key")
	}

	jm.mutex.Lock()
	defer jm.mutex.Unlock()

	jm.privateKey = privateKey
	jm.publicKey = publicKey

	klog.Infof("Loaded RSA keys from existing identity secret")
	return nil
}

func (jm *JWTManager) loadPrivateKeyPEM(secret *v1.Secret) error {
	privateKeyPEM := secret.Data[PrivateKeyDataKey]
	if len(privateKeyPEM) == 0 {
		return fmt.Errorf("private key not found in secret")
	}

	block, _ := pem.Decode(privateKeyPEM)
	if block == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	jm.mutex.Lock()
	defer jm.mutex.Unlock()

	jm.privateKey = privateKey
	return nil
}

func PrivateKeyToPEM(privateKey *rsa.PrivateKey) []byte {
	pemBlock := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	}
	return pem.EncodeToMemory(pemBlock)
}

func PublicKeyToPEM(publicKey *rsa.PublicKey) []byte {
	pubBytes, err := x509.MarshalPKIXPublicKey(publicKey)
	if err != nil {
		return nil
	}
	pemBlock := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubBytes,
	}
	return pem.EncodeToMemory(pemBlock)
}

