	if err != nil {
		return nil, err
	}

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeValkeyOptions(addr, password string, disableCache, forceSingle bool) (valkey.ClientOption, error) {
	addresses := strings.Split(addr, ",")

	initAddress := addresses
	if len(addresses) == 1 {
		initAddress = []string{addresses[0]}
	}

	opts := valkey.ClientOption{
		InitAddress:  initAddress,
		Password:     password,
		DisableCache: disableCache,
	}

	if forceSingle || len(addresses) == 1 {
		opts.AlwaysRESP2 = true
	}

	return opts, nil
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	return v.cli.Do(ctx, v.cli.B().Ping().Build()).Error()
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := v.sessionPrefix + sessionID
	result, err := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build()).AsBytes()
	if err != nil {
		if isValkeyNotFound(err) {
			return nil, ErrNotFound
		}
