	key := v.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := int64(time.Until(expiresAt).Seconds())
	if ttl <= 0 {
		ttl = int64((8 * time.Hour).Seconds())
	}

	expiryScore := float64(expiresAt.Unix())
	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	lastActivityScore := float64(lastActivity.Unix())

	commands := []valkey.Completed{
		v.cli.B().Set().Key(key).Value(string(data)).Nx().Ex(ttl).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(expiryScore, sandbox.SessionID).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(lastActivityScore, sandbox.SessionID).Build(),
	}

